/**
 *  final-input
 *  ----------
 *  Liefert EIN Item mit:
 *    • subject, mail_text, kb_entries, conversationId, messageId, customerEmail, customerMessage
 *    • generated_prompt, email_direct_send, ordner_logik
 *    • model_queries            – aus "Message a model1" (Array oder null)
 *    • model_queries_str        – gleiche Queries als String (kommasepariert)
 *    • start_time_              – aus Merge übernommen
 *    • processing_time_seconds  – Differenz zu jetzt in Sekunden
 */

/* ---------- Helpers ---------------------------------------------- */
const isKbHit   = i => i.json.ki_id !== undefined;
const hasPrompt = i =>
  i.json.generated_prompt !== undefined ||
  i.json.email_direct_send !== undefined ||
  i.json.ordner_logik !== undefined;

/* ---------- Mail-, Config- und KB-Items separieren ---------------- */
const mailItem   = items.find(i => !isKbHit(i) && !hasPrompt(i));
if (!mailItem) throw new Error('⚠️  Kein Mail-Item im Merge gefunden!');

const configItem = items.find(hasPrompt) || {};
const kbHitsRaw  = items.filter(isKbHit);

/* ---------- KB-Duplikate je chunk_id entfernen ------------------- */
const bestByChunk = {};
for (const h of kbHitsRaw.map(i => i.json)) {
  const key = h.chunk_id || `__noChunk:${h.ki_id}`;
  if (!bestByChunk[key] || (h.similarity ?? 0) > (bestByChunk[key].similarity ?? 0)) {
    bestByChunk[key] = h;
  }
}
const kb_entries = Object.values(bestByChunk)
  .sort((a,b)=>(b.similarity ?? 0) - (a.similarity ?? 0))
  .slice(0,10)
  .map(h => {
    const txt = h.chunk_content ?? h.ki_content ?? h.content ?? '[Kein Text]';
    const sim = (h.similarity ?? 0).toFixed(2);
    return `• ${txt} (Relevanz: ${sim})`;
  })
  .join('\n')
  || 'Keine Wissensdatenbank-Artikel gefunden.';

/* ---------- Mail-Basisdaten -------------------------------------- */
const {
  subject   : rawSubject,
  bodyPreview,
  _newbody,
  _newid,
  conversationId = '[keine convId]',
} = mailItem.json;

/* ---------- Sauberen Betreff bauen -------------------------------- */
const isFilled = s => typeof s === 'string' && s.trim();
const subject  = isFilled(rawSubject)
  ? rawSubject.trim().slice(0,150)
  : isFilled(bodyPreview)
    ? bodyPreview.trim().slice(0,90)
    : '[Kein Betreff/Text]';

/* ---------- Message-ID aus dem Merge übernehmen ------------------ */
const messageId = _newid || '[keine id]';

/* ---------- Kunden-E-Mail extrahieren ---------------------------- */
let customerEmail = mailItem.json.metadata?.['return-path'] || null;
if (!customerEmail && typeof _newbody === 'string') {
  const m1 = _newbody.match(/mailto:([A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,})/i);
  if (m1) {
    customerEmail = m1[1];
  } else {
    const textOnly = _newbody.replace(/<[^>]+>/g,' ');
    const m2 = textOnly.match(/[A-Z0-9._%+-]+@[A-Z0-9.-]+\.[A-Z]{2,}/i);
    if (m2) customerEmail = m2[0];
  }
}

/* ---------- Kunden-Nachricht extrahieren ------------------------ */
let customerMessage = '';
if (typeof _newbody === 'string') {
  const plain = _newbody
    .replace(/<br\s*\/?>/gi,'\n')
    .replace(/<\/p>/gi,'\n')
    .replace(/<[^>]+>/g,'')
    .replace(/&nbsp;/gi,' ')
    .replace(/\n\s*\n+/g,'\n')
    .trim();
  const marker = 'Nachricht oder Anmerkungen:';
  const idx    = plain.indexOf(marker);
  customerMessage =
    idx !== -1 ? plain.slice(idx + marker.length).trim() : plain;
}

/* ---------- Config-Werte übernehmen ------------------------------ */
const generated_prompt  = configItem.json?.generated_prompt  ?? null;
const email_direct_send = configItem.json?.email_direct_send ?? false;
const ordner_logik      = configItem.json?.ordner_logik      ?? null;

/* ---------- NEU: Queries aus "Message a model1" ------------------ */
const model_queries =
  $('Message a model2').first()?.json?.choices?.[0]?.message?.content?.queries ?? null;

const model_queries_str = Array.isArray(model_queries)
  ? model_queries.join(', ')
  : (model_queries != null ? String(model_queries) : null);

/* ---------- NEU: start_time_ & processing_time ------------------- */
const startItem = items.find(i => i.json.start_time_ !== undefined);
const start_time_ = startItem ? startItem.json.start_time_ : null;

let processing_time_seconds = null;
if (start_time_) {
  const t = Date.parse(start_time_);
  if (!Number.isNaN(t)) {
    processing_time_seconds = Math.max(0, Math.floor((Date.now() - t) / 1000));
  }
}

/* ---------- EIN Output-Item -------------------------------------- */
return [
  {
    json: {
      conversationId,
      messageId,
      subject,
      customerEmail,
      mail_text       : `<b>${subject}</b><br><br>${_newbody ?? ''}`,
      customerMessage,
      kb_entries,
      generated_prompt,
      email_direct_send,
      ordner_logik,
      model_queries,
      model_queries_str,

      // NEU
      start_time_,
      processing_time_seconds,
    }
  }
];

// Beispiel: Hardcoded user_id – kannst du später dynamisch machen
const userId = '028f7876-5c05-44ed-b34e-0d195e9e513b';

// Aktuellen Monatsanfang berechnen
const now = new Date();
const year = now.getFullYear();
const month = String(now.getMonth() + 1).padStart(2, '0'); // +1 weil getMonth() 0-basiert ist
const firstDayOfMonth = `${year}-${month}-01`;

return [
  {
    json: {
      user_id: userId,
      month_year: firstDayOfMonth,
    }
  }
];

const currentCount = $json.emails_sent_count || 0;
const newCount = currentCount + 1;

return [
  {
    json: {
      id: $json.id,
      emails_sent_count: newCount
    }
  }
];

// Beispiel: Hardcoded user_id – kannst du später dynamisch machen
const userId = '028f7876-5c05-44ed-b34e-0d195e9e513b';

// Aktuellen Monatsanfang berechnen
const now = new Date();
const year = now.getFullYear();
const month = String(now.getMonth() + 1).padStart(2, '0'); // +1 weil getMonth() 0-basiert ist
const firstDayOfMonth = `${year}-${month}-01`;

return [
  {
    json: {
      user_id: userId,
      month_year: firstDayOfMonth,
    }
  }
];

const currentCount = $json.emails_replied_count || 0;
const newCount = currentCount + 1;

return [
  {
    json: {
      id: $json.id,
      emails_replied_count: newCount
    }
  }
];

const message_id = $items('final input2')[0].json.messageId || 'MESSAGE_ID_FEHLT';
const antwort = items[1].json.output?.antwort || 'ANTWORT_FEHLT';
const direct_send = $input.first().json.email_direct_send ?? false;
const ordner = items[1].json.output?.ordner || 'ORDNER_FEHLT';
const signatur = $input.first().json.signatur || 'SIGNATUR_FEHLT';  // <--- Hier angepasst!

return [
  {
    json: {
      message_id,
      antwort,
      email_direct_send: direct_send,
      ordner,
      signatur,  // Ausgabe angepasst
    }
  }
];

const now = new Date();
const start = new Date(Date.UTC(
  now.getUTCFullYear(), now.getUTCMonth(), now.getUTCDate() - 1, 0, 0, 0
));
const end = new Date(Date.UTC(
  start.getUTCFullYear(), start.getUTCMonth(), start.getUTCDate(), 23, 59, 59
));
const trim = d => d.toISOString().replace(/\.\d{3}Z$/, 'Z');
return [{ json: { yStart: trim(start), yEnd: trim(end) } }];

// Hilfen
const stripHtml = (html = '') =>
  String(html)
    .replace(/<style[\s\S]*?<\/style>/gi, '')
    .replace(/<script[\s\S]*?<\/script>/gi, '')
    .replace(/<!--[\s\S]*?-->/g, '')
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<[^>]+>/g, '')
    .replace(/\u00A0/g, ' ')
    .replace(/[ \t]+\n/g, '\n')
    .trim();

const toArray = (value) => Array.isArray(value) ? value : (value ? [value] : []);

const pickAddress = (x) => {
  const a = x?.emailAddress || {};
  return {
    name: a.name || null,
    address: a.address || null,
  };
};

const formatDateDE = (iso) => {
  if (!iso) return null;
  const d = new Date(iso);
  const dd = String(d.getDate()).padStart(2, '0');
  const mm = String(d.getMonth() + 1).padStart(2, '0');
  const yyyy = d.getFullYear();
  return `${dd}.${mm}.${yyyy}`; // tt.MM.yyyy
};

const normalizeMessage = (m) => {
  const bodyType = (m?.body?.contentType || '').toLowerCase();
  const rawBody = m?.body?.content || '';
  const bodyText = bodyType === 'html' ? stripHtml(rawBody) : String(rawBody || '');
  const from = pickAddress(m?.from);
  const sender = pickAddress(m?.sender);

  return {
    id: m?.id || null,
    internetMessageId: m?.internetMessageId || null,
    subject: m?.subject || '',
    importance: m?.importance || 'normal',
    isRead: !!m?.isRead,
    hasAttachments: !!m?.hasAttachments,
    receivedAt: m?.receivedDateTime || null,
    receivedAtDisplay: formatDateDE(m?.receivedDateTime),
    sentAt: m?.sentDateTime || null,
    sentAtDisplay: formatDateDE(m?.sentDateTime),
    webLink: m?.webLink || null,

    from,
    sender,
    to: toArray(m?.toRecipients).map(pickAddress),
    cc: toArray(m?.ccRecipients).map(pickAddress),
    bcc: toArray(m?.bccRecipients).map(pickAddress),

    // Vorschau + gereinigter Body
    bodyPreview: m?.bodyPreview || bodyText.slice(0, 240),
    bodyText,
    bodyHtml: bodyType === 'html' ? rawBody : null,

    // Konversation/Ordner
    conversationId: m?.conversationId || null,
    parentFolderId: m?.parentFolderId || null,
  };
};

// Eingabe holen: deine Items sind rohe Graph-Messages
const inputItems = $input.all(); // [{ json: <graph-message> }, ...] oder [{json: {...}}]

const normalized = inputItems.map((it) => {
  const m = it.json || it; // robust gegen unterschiedliche Formen
  return { json: normalizeMessage(m) };
});

// Optional: Duplikate nach id oder internetMessageId entfernen
const seen = new Set();
const deduped = normalized.filter(({ json }) => {
  const key = json.id || json.internetMessageId;
  if (!key) return true;
  if (seen.has(key)) return false;
  seen.add(key);
  return true;
});

return deduped;

