// n8n Code Node (JavaScript)
// NUR bodyPreview verwenden (kein body.content).
// Gibt EIN Item zurück: { structured: {...}, prompt_text: "..." }
// Zusätzlich bekommt jede Email eine laufende seq_id (0..x).
// WICHTIG: Die originale Provider-ID (m.id) wird in structured gespeichert,
// erscheint aber NICHT im prompt_text.

const TZ = "Europe/Berlin";
const BODY_CHAR_LIMIT = 0;           // >0 setzen, um Body zu kappen (Tokens sparen)
const INCLUDE_EMPTY_DAYS = false;    // true => Tage ohne Mails aufführen

function normalizePreview(txt) {
  if (!txt) return "";
  return String(txt)
    .replace(/\r\n/g, "\n")
    .replace(/\u00A0/g, " ")
    .replace(/[ \t]+\n/g, "\n")
    .replace(/\n{3,}/g, "\n\n")
    .replace(/[ \t]{2,}/g, " ")
    .trim();
}

function getLocalParts(iso) {
  const d = iso ? new Date(iso) : new Date();
  const dateParts = new Intl.DateTimeFormat("de-DE", {
    timeZone: TZ, year: "numeric", month: "2-digit", day: "2-digit"
  }).formatToParts(d);
  const [{ value: day }, , { value: month }, , { value: year }] = dateParts;
  const weekday = new Intl.DateTimeFormat("de-DE", { timeZone: TZ, weekday: "long" })
    .format(d)
    .replace(/^\w/u, c => c.toUpperCase());
  return { date: `${year}-${month}-${day}`, weekday };
}

const weekdayOrder = ["Montag","Dienstag","Mittwoch","Donnerstag","Freitag","Samstag","Sonntag"];
const pickDate = (m) => m.receivedDateTime || m.sentDateTime || m.createdDateTime || null;

const items = $input.all();
const dayBuckets = new Map();
let minDate = null, maxDate = null;

// --- E-Mails einsammeln ---
for (const it of items) {
  const m = it.json || {};
  const when = pickDate(m);
  const { date, weekday } = getLocalParts(when);

  let bodyText = normalizePreview(m.bodyPreview || "");
  if (BODY_CHAR_LIMIT > 0 && bodyText.length > BODY_CHAR_LIMIT) {
    bodyText = bodyText.slice(0, BODY_CHAR_LIMIT).trim() + " …";
  }

  if (!dayBuckets.has(date)) dayBuckets.set(date, { day: weekday, date, emails: [] });
  dayBuckets.get(date).emails.push({
    id: m.id || null,                          // <-- Provider-ID wieder hinzufügen
    subject: (m.subject || "").trim(),
    emailtext: bodyText
  });

  const dt = new Date(when || Date.now());
  if (!minDate || dt < minDate) minDate = dt;
  if (!maxDate || dt > maxDate) maxDate = dt;
}

// Optional: leere Tage ergänzen
if (INCLUDE_EMPTY_DAYS && minDate && maxDate) {
  const DAY_MS = 24 * 60 * 60 * 1000;
  for (let t = new Date(minDate).setUTCHours(0,0,0,0);
       t <= new Date(maxDate).setUTCHours(0,0,0,0);
       t += DAY_MS) {
    const iso = new Date(t).toISOString();
    const { date, weekday } = getLocalParts(iso);
    if (!dayBuckets.has(date)) dayBuckets.set(date, { day: weekday, date, emails: [] });
  }
}

// Sortierung: Mo..So, dann Datum
const days = Array.from(dayBuckets.values()).sort((a, b) => {
  const wd = weekdayOrder.indexOf(a.day) - weekdayOrder.indexOf(b.day);
  if (wd !== 0) return wd;
  return a.date.localeCompare(b.date);
});

// --- Laufende IDs (seq_id) vergeben: 0..x in der sichtbaren Reihenfolge ---
let seq = 0;
for (const d of days) {
  for (const e of d.emails) {
    e.seq_id = seq++;     // neue fortlaufende ID
  }
}

// Prompt-Text bauen (mit seq_id, ohne Provider-ID)
let promptLines = [];
for (const d of days) {
  promptLines.push(`${d.day} (${d.date})`);
  for (const e of d.emails) {
    promptLines.push(
      `email ${e.seq_id}: "Subject: ${e.subject.replace(/"/g, '\\"')}, ` +
      `Emailtext: ${e.emailtext.replace(/"/g, '\\"')}"`
    );
  }
  promptLines.push("");
}
const prompt_text = promptLines.join("\n").trim();

// mail_count pro Tag ergänzen
for (const d of days) {
  d.mail_count = d.emails.length;
}

// mail_count gesamt berechnen
const total_mail_count = days.reduce((sum, d) => sum + d.mail_count, 0);

const structured = {
  range: {
    start: minDate ? getLocalParts(minDate.toISOString()).date : null,
    end:   maxDate ? getLocalParts(maxDate.toISOString()).date : null,
    timezone: TZ
  },
  mail_count: total_mail_count,
  days
};

return [{ json: { structured, prompt_text } }];

// n8n Code Node (JavaScript)
// Aggregiert Model-Output zu: result = [{ date, trends: [{ trendthema, count, email_seq_ids, email_ids }] }, ...]
// Und hängt neue_trendthema_vorschlaege als eigenen Block ans result an:
// { date: "neue_trendthema_vorschlaege", trends: [{ trendthema: "..." }, ...] }

function getISOWeek(date) {
  const tmp = new Date(date);
  tmp.setHours(0, 0, 0, 0);
  tmp.setDate(tmp.getDate() + 3 - ((tmp.getDay() + 6) % 7));
  const week1 = new Date(tmp.getFullYear(), 0, 4);
  return 1 + Math.round(
    ((tmp.getTime() - week1.getTime()) / 86400000 - 3 + ((week1.getDay() + 6) % 7)) / 7
  );
}

const DATE_RE = /^\d{4}-\d{2}-\d{2}$/;

const inputs = $input.all();

// 1) Model-Output (wir nehmen das erste Item mit message.content, sonst inputs[0])
const modelItem = inputs.find(it => it.json?.message?.content) ?? inputs[0];
const content = modelItem?.json?.message?.content ?? {};

// 2) Optionales Mapping seq_id -> echte email_id aus structured.days[*].emails
const seqToId = new Map();
for (const it of inputs) {
  const days = it.json?.structured?.days;
  if (Array.isArray(days)) {
    for (const d of days) {
      const emails = Array.isArray(d.emails) ? d.emails : [];
      for (const e of emails) {
        if (typeof e.seq_id === "number") {
          seqToId.set(String(e.seq_id), e.id ?? null);
        }
      }
    }
  }
}

// ---------------------------------------------------------
// Aggregation
const perDay = new Map(); // date -> Map(trendthema -> { email_seq_ids:Set<number>, email_ids:Set<string|null> })
let earliestDate = null;
let totalCount = 0;

for (const [dateKey, items] of Object.entries(content)) {
  if (!DATE_RE.test(dateKey)) continue; // z. B. "neue_trendthema_vorschlaege" überspringen

  const list = Array.isArray(items) ? items : [];
  if (!perDay.has(dateKey)) perDay.set(dateKey, new Map());
  const trendMap = perDay.get(dateKey);

  for (const row of list) {
    const thema = row?.trendthema || "Unbekannt";
    const seqStr = row?.email != null ? String(row.email) : null;
    if (!seqStr) continue;

    if (!trendMap.has(thema)) {
      trendMap.set(thema, { email_seq_ids: new Set(), email_ids: new Set() });
    }
    const bucket = trendMap.get(thema);

    // seq_id aufnehmen
    const seqNum = Number(seqStr);
    bucket.email_seq_ids.add(seqNum);

    // echte email_id (falls Mapping vorhanden)
    if (seqToId.has(seqStr)) {
      bucket.email_ids.add(seqToId.get(seqStr));
    }

    totalCount++;
  }

  const d = new Date(dateKey);
  if (!earliestDate || d < earliestDate) earliestDate = d;
}

// ---------------------------------------------------------
// result bauen (pro Datum sortiert, in jedem Datum Trends nach count desc)
const result = Array.from(perDay.entries())
  .map(([date, trendMap]) => {
    const trends = Array.from(trendMap.entries())
      .map(([trendthema, sets]) => ({
        trendthema,
        count: sets.email_seq_ids.size,
        email_seq_ids: Array.from(sets.email_seq_ids).sort((a, b) => a - b),
        email_ids: Array.from(sets.email_ids),
      }))
      .sort((a, b) => b.count - a.count || a.trendthema.localeCompare(b.trendthema, "de"));
    return { date, trends };
  })
  .sort((a, b) => a.date.localeCompare(b.date));

// ---------------------------------------------------------
// neue_trendthema_vorschlaege ans result ANHÄNGEN (am Ende)
if (Array.isArray(content.neue_trendthema_vorschlaege) && content.neue_trendthema_vorschlaege.length > 0) {
  const suggestionTrends = content.neue_trendthema_vorschlaege.map(name => ({ trendthema: name }));
  result.push({
    date: "neue_trendthema_vorschlaege",
    trends: suggestionTrends
  });
}

// Meta
const calender_week = earliestDate ? getISOWeek(earliestDate) : null;

return [{
  json: {
    result,
    meta: {
      mail_count: totalCount,
      calender_week
    }
  }
}];

const msg = $json;
const message_id = msg.id || msg.internetMessageId;
const user_id    = "euronics";   // optional, oder weglassen
const toEmail    = msg.toRecipients?.[0]?.emailAddress?.address;

const exp = Math.floor(Date.now()/1000) + 7*24*3600; // 7 Tage gültig

const out = [];
for (const score of [5,4,3,2,1]) {
  out.push({
    json: {
      message_id,
      user_id,
      toEmail,
      score,
      exp,
      payload: `${user_id}|${message_id}|${score}|${exp}`
    }
  });
}
return out;

const baseUrl = 'https://automation.ecomtask.de/webhook/ecomtask';

// Helper zum Querystring bauen
function qs(obj) {
  return Object.entries(obj)
    .map(([k, v]) => `${encodeURIComponent(k)}=${encodeURIComponent(String(v))}`)
    .join('&');
}

const all = $items(); 

// Annahme: Der erste Input enthält die Benutzerdaten (aus "Get a row")
// und die restlichen die Bewertungsdaten.
// Wir extrahieren die Vorlage aus dem ersten Item, das sie enthält.
const userProfileItem = all.find(item => item.json.rating_email_template);
const userEmailTemplate = userProfileItem ? userProfileItem.json.rating_email_template : "Hallo,\n\nbitte bewerten Sie unseren Service.\n\n{{bewertung_links}}\n\nDanke!";


// Gruppieren der Bewertungsdaten nach message_id
const grouped = new Map();
for (const it of all) {
  // Überspringe die Profildaten, falls sie als separate Items ankommen
  if (it.json.rating_email_template) continue; 

  const j = it.json;
  if (!grouped.has(j.message_id)) grouped.set(j.message_id, []);
  grouped.get(j.message_id).push(j);
}


const out = [];
for (const [message_id, arr] of grouped.entries()) {
  const meta = arr[0];
  const toEmail = meta.toEmail;
  if (!toEmail) continue;

  // Sortieren 5 → 1
  arr.sort((a, b) => b.score - a.score);

  // Links aufbauen
  const links = arr.map(a => {
    const url = `${baseUrl}?${qs({
      u: a.user_id,
      m: a.message_id,
      s: a.score,
      exp: a.exp,
      sig: a.sig
    })}`;
    return `<a href="${url}" style="text-decoration:none">` + '⭐️'.repeat(a.score) + `</a>`;
  }).join(' | ');

  // Der HTML-Block für die Links, jetzt ohne die Überschrift
  const bewertung_links_html = `
<div style="margin-top:12px;padding-top:10px;border-top:1px solid #eee;">
  <div>${links}</div>
  <div style="font-size:12px;color:#666;margin-top:6px">Ein Klick genügt.</div>
</div>`.trim();

  // Ersetze den Platzhalter in der Vorlage
  let final_email_body = userEmailTemplate.replace('{{bewertung_links}}', bewertung_links_html)
