function htmlToPlainText(html) {
  if (typeof html !== 'string') return '';

  return html
    .replace(/<br\s*\/?>/gi, '\n')
    .replace(/<\/p>/gi, '\n')
    .replace(/<[^>]+>/g, '')
    .replace(/&nbsp;/gi, ' ')
    .replace(/\n\s*\n+/g, '\n')
    .trim();
}

